#!/usr/bin/env node
// Generate the figure-data CSVs that don't need the live DB:
//   fig3a_source_stratification.csv  (paper-frozen FIG_3A)
//   fig2_benchmark.csv                (filtered BENCHMARK_TABLE: 'all' stratum)
//   figS1_metal_stratification.csv    (filtered BENCHMARK_TABLE: metal-binding stratified rows)
//   fig4_af_geometric.csv             (mirror of manuscript fig3_paired_distances.tsv)
//
// Reads:
//   src/lib/data/benchmark_metrics.json  (regenerated by scripts/etl/benchmark_web_panels.py)
//   ~/work/small_metal_binders_2026/paper/figure_data/fig3_paired_distances.tsv
//
// FIG_3A is mirrored verbatim from src/lib/paperData.ts so the CSV
// matches the paper-frozen Fig 3A panel; if paperData.ts is updated,
// also update FIG_3A_ROWS below.

import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';

const repoRoot = path.resolve(path.dirname(new URL(import.meta.url).pathname), '..');
const outDir = process.env.OUT_DIR
  || path.join(repoRoot, 'public/data/figure_data');
fs.mkdirSync(outDir, { recursive: true });

// ---------- Helpers ----------
function csvEscape(v) {
  const s = v === null || v === undefined ? '' : String(v);
  return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}
function writeCsv(filename, header, rows) {
  const out = path.join(outDir, filename);
  const lines = [header.join(',')];
  for (const row of rows) lines.push(row.map(csvEscape).join(','));
  fs.writeFileSync(out, lines.join('\n') + '\n');
  console.log(`  wrote ${out} (${rows.length} rows)`);
}

// ---------- Fig 3A: paper-frozen source-stratified rates ----------
// Mirror of src/lib/paperData.ts FIG_3A. Update both together when the
// manuscript publishes a refreshed Fig 3A.
const FIG_3A_ROWS = [
  { source: 'PDB-geom', nDomains: 157480, freeThiolFrac: 0.668, disulfideFrac: 0.241, metalFrac: 0.091 },
  { source: 'PDB-ESM',  nDomains: 157480, freeThiolFrac: 0.741, disulfideFrac: 0.187, metalFrac: 0.072 },
  { source: 'AFDB-ESM', nDomains: 533598, freeThiolFrac: 0.785, disulfideFrac: 0.157, metalFrac: 0.058 },
];
writeCsv(
  'fig3a_source_stratification.csv',
  ['source', 'n_domains', 'free_thiol_frac', 'disulfide_frac', 'metal_frac'],
  FIG_3A_ROWS.map((r) => [r.source, r.nDomains, r.freeThiolFrac, r.disulfideFrac, r.metalFrac]),
);

// ---------- Fig 2 + Fig S1: from benchmark_metrics.json ----------
const metricsPath = path.join(repoRoot, 'src/lib/data/benchmark_metrics.json');
const metrics = JSON.parse(fs.readFileSync(metricsPath, 'utf8'));
const allMetrics = metrics.metrics; // [{tool, task, stratum, auroc, ap, n_pos, n_total}]

// Fig 2 = the all-stratum rows (ROC + PR figures show these numbers).
const fig2Rows = allMetrics.filter((r) => r.stratum === 'all');
writeCsv(
  'fig2_benchmark.csv',
  ['tool', 'task', 'stratum', 'auroc', 'ap', 'n_pos', 'n_total'],
  fig2Rows.map((r) => [r.tool, r.task, r.stratum, r.auroc, r.ap, r.n_pos, r.n_total]),
);

// Fig S1 = metal-binding × the metal-type strata (everything except 'all').
const figS1Rows = allMetrics.filter(
  (r) => r.task === 'metal_binding' && r.stratum !== 'all',
);
writeCsv(
  'figS1_metal_stratification.csv',
  ['tool', 'task', 'stratum', 'auroc', 'ap', 'n_pos', 'n_total'],
  figS1Rows.map((r) => [r.tool, r.task, r.stratum, r.auroc, r.ap, r.n_pos, r.n_total]),
);

// ---------- Fig 4: AlphaFold geometric scanning paired distances ----------
// Mirror of the manuscript's fig3_paired_distances.tsv (renumbered to
// Fig 4 on the website per the v2 figure-order). Each row is a single
// cysteine in a domain with the nearest-cys Sγ-Sγ distance, separately
// for the matched PDB structure and the AFDB-monomer model.
const manuscriptFig4 = path.join(
  os.homedir(),
  'work/small_metal_binders_2026/paper/figure_data/fig3_paired_distances.tsv',
);
const fig4Out = path.join(outDir, 'fig4_af_geometric.csv');
if (fs.existsSync(manuscriptFig4)) {
  const tsv = fs.readFileSync(manuscriptFig4, 'utf8').trimEnd().split('\n');
  const header = tsv[0].split('\t');
  const lines = [header.join(',')];
  for (let i = 1; i < tsv.length; i++) {
    lines.push(tsv[i].split('\t').map(csvEscape).join(','));
  }
  fs.writeFileSync(fig4Out, lines.join('\n') + '\n');
  console.log(`  wrote ${fig4Out} (${tsv.length - 1} rows from manuscript fig3_paired_distances.tsv)`);
} else {
  console.warn(
    `  skipped fig4_af_geometric.csv — manuscript source not found at ${manuscriptFig4}`,
  );
}

console.log('Done (static CSVs).');
